async function saveArticles(articles) {
  if (articles.length === 0) { console.log('\n⚠️ No articles to save.'); return; }
  console.log(`\n💾 Saving ${articles.length} articles to Supabase...`);
  let saved = 0, skipped = 0;
  for (let i = 0; i < articles.length; i += 20) {
    const batch = articles.slice(i, i + 20);
    const { error } = await supabase.from('articles').upsert(batch, { onConflict: 'title', ignoreDuplicates: true });
    if (error) {
      for (const a of batch) {
        const { error: e2 } = await supabase.from('articles').insert(a);
        if (e2) skipped++; else saved++;
      }
    } else { saved += batch.length; }
  }
  console.log(`  ✅ Saved: ${saved}, Skipped: ${skipped}`);
}

function formatArticles(articles, grade, contentSource, difficulty) {
  return articles.map(a => ({
    title: a.title,
    summary: a.content.substring(0, 250).trim() + (a.content.length > 250 ? '...' : ''),
    content: a.content,
    source_name: contentSource === 'elementary' ? `译林版小学英语 - ${grade}` : `译林版高中英语 - ${grade}`,
    source_url: '',
    content_source: contentSource,
    difficulty,
    grade,
    published_at: new Date().toISOString(),
  }));
}

